body { font-family: Arial, sans-serif; margin: 20px; background-color: #f4f4f9; color: #333; display: flex; flex-direction: column; height: 95vh; }
textarea { width: 100%; height: 150px; margin-bottom: 10px; padding: 10px; border: 1px solid #ccc; border-radius: 4px; box-sizing: border-box; }
button { background-color: #28a745; color: white; border: none; padding: 10px 15px; cursor: pointer; border-radius: 4px; font-size: 16px; margin-bottom: 15px; align-self: flex-start; }
button:hover { background-color: #218838; }
iframe { flex-grow: 1; width: 100%; border: 2px solid #ccc; border-radius: 4px; background: white; }
.engine-container { display: flex; flex-direction: column; flex-grow: 1; }

function renderJSONEngine() {
    const jsonString = document.getElementById('jsonInput').value;
    if (!jsonString.trim()) {
        alert('Kripya pehle JSON data paste karein!');
        return;
    }

    try {
        const data = JSON.parse(jsonString);
        const iframe = document.getElementById('outputScreen');
        const iframeDoc = iframe.contentDocument || iframe.contentWindow.document;

        // Document clear karein
        iframeDoc.open();
        iframeDoc.write("<!DOCTYPE html><html><head></head><body></body></html>");
        iframeDoc.close();

        // 1. Set Title
        if (data.head && data.head.title) {
            iframeDoc.title = data.head.title;
        }

        // 2. Inject Meta Tags
        if (data.head && data.head.meta) {
            data.head.meta.forEach(metaData => {
                const meta = iframeDoc.createElement('meta');
                Object.keys(metaData).forEach(key => {
                    meta.setAttribute(key, metaData[key]);
                });
                iframeDoc.head.appendChild(meta);
            });
        }

        // 3. Inject External CSS
        if (data.css && data.css.external) {
            data.css.external.forEach(href => {
                const link = iframeDoc.createElement('link');
                link.rel = 'stylesheet';
                link.href = href;
                iframeDoc.head.appendChild(link);
            });
        }

        // 4. Inject Internal CSS
        if (data.css && data.css.internal) {
            data.css.internal.forEach(cssText => {
                const style = iframeDoc.createElement('style');
                style.textContent = cssText;
                iframeDoc.head.appendChild(style);
            });
        }

        // 5. Inject Body HTML
        if (data.body && data.body.html) {
            iframeDoc.body.innerHTML = data.body.html;
        }

        // 6. Inject External Scripts
        if (data.script && data.script.external) {
            data.script.external.forEach(src => {
                const script = iframeDoc.createElement('script');
                script.src = src;
                script.async = false; // Sequence barkarar rakhne ke liye
                iframeDoc.body.appendChild(script);
            });
        }

        // 7. Inject Internal Scripts
        if (data.script && data.script.internal) {
            data.script.internal.forEach(jsText => {
                const script = iframeDoc.createElement('script');
                script.textContent = jsText;
                iframeDoc.body.appendChild(script);
            });
        }

    } catch (error) {
        alert("Invalid JSON format! Kripya sahi JSON paste karein. Error: " + error.message);
    }
}
